External knowledge: 
- The interaction type 'Call' refers to a specific type of interaction.
; 
- The access type 'view' implies that the user has viewed the contact's information.
; 
- The specific date '2023-05-01' refers to May 1, 2023.

sql:
SELECT fullname
FROM contacts
WHERE contact_id IN (
    SELECT contact_id
    FROM contact_interactions
);

SELECT COUNT(*) AS count_of_email_contacts
FROM contact_preferences
WHERE communication_pref = 'Email' AND marketing_opt_in = 1;

SELECT contact_id, street
FROM contact_addresses
WHERE is_primary = 1;
